module mul_4bit (
    input wire [3:0] A,
    input wire [3:0] B,
    output wire [7:0] result
    );

reg [7:0] _inv_product;
integer i;

always@(*) begin
    _inv_product = 8'b0;
    for (i = 0; i < 4; i = i + 1) begin
        if (A[i]) begin
            _inv_product = _inv_product + (B << i);
        end
    end
end

assign result = _inv_product;

endmodule
